304→            const posInSection = prev - sectionStart;
305→            const row = Math.floor(posInSection / COLUMNS);
306→            const col = posInSection % COLUMNS;
307→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
308→
309→            if (row + 1 < sectionRows) {
310→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
311→              return nextIdx < sectionStart + sectionLength
312→                ? nextIdx
313→                : sectionStart + sectionLength - 1;
314→            }
315→
316→            const nextSectionStart = sectionStart + sectionLength;
317→            if (nextSectionStart < totalCount) {
318→              const nextInfo = getSectionInfo(nextSectionStart);
319→              if (!nextInfo) return prev;
320→              const targetIdx = nextSectionStart + col;
321→              return targetIdx < nextSectionStart + nextInfo.sectionLength
322→                ? targetIdx
323→                : nextSectionStart + nextInfo.sectionLength - 1;
324→            }
325→
326→            return prev;
327→          });
328→          break;
329→        }
330→        case 'ArrowUp': {
331→          e.preventDefault();
332→          setActiveIndex(prev => {
333→            const sectionInfo = getSectionInfo(prev);
334→            if (!sectionInfo) return prev;
335→            const { sectionStart } = sectionInfo;
336→            const posInSection = prev - sectionStart;
337→            const row = Math.floor(posInSection / COLUMNS);
338→            const col = posInSection % COLUMNS;
339→
340→            if (row > 0) {
341→              return sectionStart + (row - 1) * COLUMNS + col;
342→            }
343→
344→            if (sectionStart > 0) {
345→              const prevSectionEnd = sectionStart - 1;
346→              const prevInfo = getSectionInfo(prevSectionEnd);
347→              if (!prevInfo) return prev;
348→              const prevSectionRows = Math.ceil(
349→                prevInfo.sectionLength / COLUMNS,
350→              );
351→              const lastRowStart =
352→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
353→              const targetIdx = lastRowStart + col;
354→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
355→                ? targetIdx
356→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
357→            }
358→
359→            return prev;
360→          });
361→          break;
362→        }
363→        case 'Enter': {
364→          e.preventDefault();
365→          handleCopyEmoji();
366→          break;
367→        }
368→      }
369→    }
370→
371→    window.addEventListener('keydown', handleKeyDown);
372→    return () => window.removeEventListener('keydown', handleKeyDown);
373→  }, [
374→    totalCount,
375→    actionsOpen,
376→    handleCopyEmoji,
377→    sections,
378→  ]);
379→
380→  const sectionBoundaries = useMemo(() => {
