292→  const [query, setQuery] = useState('');
293→  const [selectedIndex, setSelectedIndex] = useState(0);
294→  const [actionsOpen, setActionsOpen] = useState(false);
295→  const [subView, setSubView] = useState<NoteSubView>('list');
296→  const [editingNote, setEditingNote] = useState<NoteEntry | undefined>();
297→  const { items: hudItems, show: showHUD } = useHUD();
298→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
299→
300→  useEffect(() => {
301→    let aborted = false;
302→
303→    noteDb
304→      .getAll()
305→      .then(rows => {
306→        if (aborted) return;
307→        if (rows.length > 0) {
308→          setEntries(rows.map(rowToEntry));
309→        } else if (!isTauri) {
310→          const mock = MOCK_NOTE_ENTRIES.map(e => ({ ...e }));
311→          setEntries(mock);
312→          Promise.all(mock.map(e => noteDb.insert(entryToRow(e)))).catch(
313→            console.error,
314→          );
315→        }
316→      })
317→      .catch(err => {
318→        console.error('Failed to load notes:', err);
319→        if (!isTauri && !aborted) {
320→          setEntries(MOCK_NOTE_ENTRIES.map(e => ({ ...e })));
321→        }
322→      });
323→
324→    return () => {
325→      aborted = true;
326→    };
327→  }, []);
328→
329→  const dbSearchFn = useCallback((q: string) => noteDb.search(q), []);
330→  const { results: ftsResults, invalidate: invalidateFts } = useDbSearch(
331→    query,
332→    dbSearchFn,
333→    rowToEntry,
334→  );
335→
336→  const filtered = useMemo(() => {
337→    const items = ftsResults ?? entries;
338→    if (!ftsResults && query) {
339→      return items.filter(
340→        e => fuzzyMatch(query, e.title) || fuzzyMatch(query, e.content),
341→      );
342→    }
343→    return items;
344→  }, [
345→    entries,
346→    query,
347→    ftsResults,
348→  ]);
349→
350→  const totalItemCount = filtered.length;
351→
352→  useEffect(() => {
