 115→function formatTime(time: string): string {
 116→  const parts = time.split(':').map(Number);
 117→  const hours = parts[0];
 118→  const minutes = parts[1];
 119→  if (
 120→    hours === undefined ||
 121→    isNaN(hours) ||
 122→    minutes === undefined ||
 123→    isNaN(minutes)
 124→  ) {
 125→    return time || '--:--';
 126→  }
 127→  const period = hours >= 12 ? 'PM' : 'AM';
 128→  const h = hours % 12 || 12;
 129→  return `${h}:${String(minutes).padStart(2, '0')} ${period}`;
 130→}
 131→
 132→function formatDueLabel(dueDate: Date, renderNow: Date): string {
 133→  const todayStart = new Date(renderNow);
 134→  todayStart.setHours(0, 0, 0, 0);
 135→  const dueStart = new Date(dueDate);
 136→  dueStart.setHours(0, 0, 0, 0);
 137→
 138→  const diffDays = Math.round(
 139→    (dueStart.getTime() - todayStart.getTime()) / (1000 * 60 * 60 * 24),
 140→  );
 141→
 142→  if (diffDays === 0) return 'Today';
 143→  if (diffDays === 1) return 'Tomorrow';
 144→  if (diffDays === -1) return 'Yesterday';
 145→  if (diffDays < 0) return `${Math.abs(diffDays)} days overdue`;
 146→  if (diffDays <= 7) return `In ${diffDays} days`;
 147→  return dueDate.toLocaleDateString(undefined, {
 148→    month: 'short',
 149→    day: 'numeric',
 150→  });
 151→}
 152→
 153→function repeatLabel(repeat: RepeatOption): string {
 154→  const found = REPEAT_OPTIONS.find(r => r.value === repeat);
 155→  return found?.label ?? 'None';
 156→}
 157→
 158→function isSameDay(a: Date, b: Date): boolean {
 159→  return (
 160→    a.getFullYear() === b.getFullYear() &&
 161→    a.getMonth() === b.getMonth() &&
 162→    a.getDate() === b.getDate()
 163→  );
 164→}
 165→
 166→function rowToEntry(row: ReminderRow): ReminderEntry {
 167→  const dueDate = new Date(row.due_date);
 168→  const completedAt = row.completed_at ? new Date(row.completed_at) : null;
 169→  const createdAt = new Date(row.created_at);
 170→  return {
 171→    id: row.id,
 172→    title: row.title,
 173→    dueDate: isNaN(dueDate.getTime()) ? new Date() : dueDate,
 174→    dueTime: row.due_time,
 175→    repeat: isRepeatOption(row.repeat) ? row.repeat : 'none',
 176→    notes: row.notes,
 177→    completed: row.completed === 1,
 178→    completedAt:
 179→      completedAt && !isNaN(completedAt.getTime()) ? completedAt : null,
 180→    createdAt: isNaN(createdAt.getTime()) ? new Date() : createdAt,
 181→  };
 182→}
 183→
 184→function entryToRow(entry: ReminderEntry): ReminderRow {
 185→  return {
 186→    id: entry.id,
 187→    title: entry.title,
 188→    due_date: entry.dueDate.toISOString(),
 189→    due_time: entry.dueTime,
 190→    repeat: entry.repeat,
 191→    notes: entry.notes,
 192→    completed: entry.completed ? 1 : 0,
 193→    completed_at: entry.completedAt?.toISOString() ?? null,
 194→    created_at: entry.createdAt.toISOString(),
 195→  };
 196→}
