 373→
 374→  useEffect(() => {
 375→    let aborted = false;
 376→
 377→    reminderDb
 378→      .getAll()
 379→      .then(rows => {
 380→        if (aborted) return;
 381→        if (rows.length > 0) {
 382→          setEntries(rows.map(rowToEntry));
 383→        } else if (!isTauri) {
 384→          const mock = MOCK_REMINDER_ENTRIES.map(e => ({ ...e }));
 385→          setEntries(mock);
 386→          Promise.all(mock.map(e => reminderDb.insert(entryToRow(e)))).catch(
 387→            console.error,
 388→          );
 389→        }
 390→      })
 391→      .catch(err => {
 392→        console.error('Failed to load reminders:', err);
 393→        if (!isTauri && !aborted) {
 394→          setEntries(MOCK_REMINDER_ENTRIES.map(e => ({ ...e })));
 395→        }
 396→      });
 397→
 398→    return () => {
 399→      aborted = true;
 400→    };
 401→  }, []);
 402→
 403→  const dbSearchFn = useCallback((q: string) => reminderDb.search(q), []);
 404→  const { results: ftsResults, invalidate: invalidateFts } = useDbSearch(
 405→    query,
 406→    dbSearchFn,
 407→    rowToEntry,
 408→  );
 409→
 410→  const filtered = useMemo(() => {
 411→    let items = ftsResults ?? entries;
 412→
 413→    if (filterValue === 'active') {
 414→      items = items.filter(e => !e.completed);
 415→    } else if (filterValue === 'completed') {
 416→      items = items.filter(e => e.completed);
 417→    }
 418→
 419→    if (!ftsResults && query) {
 420→      items = items.filter(
 421→        e => fuzzyMatch(query, e.title) || fuzzyMatch(query, e.notes),
 422→      );
 423→    }
 424→
 425→    return items;
 426→  }, [
 427→    entries,
 428→    query,
 429→    filterValue,
 430→    ftsResults,
 431→  ]);
 432→
 433→  const renderNow = useMemo(() => new Date(), []);
 434→
 435→  const sections = useMemo(() => {
 436→    const todayStart = new Date(renderNow);
 437→    todayStart.setHours(0, 0, 0, 0);
 438→    const tomorrowStart = new Date(todayStart);
 439→    tomorrowStart.setDate(tomorrowStart.getDate() + 1);
 440→
 441→    const overdue: ReminderEntry[] = [];
 442→    const today: ReminderEntry[] = [];
 443→    const upcoming: ReminderEntry[] = [];
 444→    const completed: ReminderEntry[] = [];
 445→
 446→    for (const entry of filtered) {
 447→      if (entry.completed) {
 448→        completed.push(entry);
 449→        continue;
 450→      }
 451→      const dueStart = new Date(entry.dueDate);
 452→      dueStart.setHours(0, 0, 0, 0);
 453→
 454→      if (dueStart.getTime() < todayStart.getTime()) {
 455→        overdue.push(entry);
 456→      } else if (isSameDay(dueStart, todayStart)) {
 457→        today.push(entry);
 458→      } else {
 459→        upcoming.push(entry);
 460→      }
 461→    }
 462→
 463→    return {
 464→      overdue,
 465→      today,
 466→      upcoming,
